mapper.select:
    	/* com.erns.coching.notification.mapper.NotificationDAO.getList */

    	SELECT B.* FROM (
			SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() AS TOTAL FROM (
					SELECT

				    FROM  T_NOTIFICATION AA



				ORDER BY
				CASE WHEN AA.CHK_YN = 'N' THEN 1 ELSE 2 END,  -- CHK_YN이 N인 것을 우선
				AA.RGT_DTTM DESC
			) A
		) B

	    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

mapper.insert:
    	/* com.erns.coching.notification.mapper.NotificationDAO.insert */


			SELECT nextval('seq_t_notification')


    	INSERT INTO T_NOTIFICATION (
			NOTI_SEQ
			, MEMB_SEQ
			, REF_CODE
			, REF_SEQ
			, CONTENT
			, CHK_YN
			, RGTR
			, RGT_DTTM
    	) VALUES (
			  #{notiSeq		, jdbcType=INTEGER}
			, #{membSeq		, jdbcType=INTEGER}
			, #{refCode		, jdbcType=VARCHAR}
			, #{refSeq		, jdbcType=INTEGER}
			, #{content		, jdbcType=VARCHAR}
			, COALESCE(#{chkYn	, jdbcType=CHAR}, 'N')
			, #{rgtr		, jdbcType=INTEGER}
			, now()
    	)

mapper.update:
    	/* com.erns.coching.notification.mapper.NotificationDAO.updateChkYn */

    	UPDATE T_NOTIFICATION SET
			  CHK_YN				= COALESCE(#{chkYn	, jdbcType=VARCHAR}, 'N')

			AND NOTI_SEQ		= #{notiSeq	, jdbcType=INTEGER}
